public boolean in1To10(int n, boolean outsideMode) {
    if (outsideMode) {
        // If outsideMode is true, return true if n is <= 1 or >= 10
        return n <= 1 || n >= 10;
    } else {
        // If outsideMode is false, return true if n is between 1 and 10 (inclusive)
        return n >= 1 && n <= 10;
    }
}

