public int luckySum(int a, int b, int c) {
    int sum = 0;

    if (a == 13) {
        return sum; // If a is 13, we ignore a, b, and c
    } else {
        sum += a;
    }

    if (b == 13) {
        return sum; // If b is 13, we ignore b and c
    } else {
        sum += b;
    }

    if (c == 13) {
        return sum; // If c is 13, we ignore c
    } else {
        sum += c;
    }

    return sum;
}

