public int sum67(int[] nums) {
    if (nums == null || nums.length == 0) {
        return 0;
    }

    int sum = 0;
    boolean ignoreSection = false;

    for (int num : nums) {
        if (num == 6) {
            ignoreSection = true;
        } else if (ignoreSection && num == 7) {
            ignoreSection = false;
        } else if (!ignoreSection) {
            sum += num;
        }
    }

    return sum;
}

