public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        // On vacation
        if (day == 0 || day == 6) {
            return "off"; // Weekend and on vacation
        } else {
            return "10:00"; // Weekday and on vacation
        }
    } else {
        // Not on vacation
        if (day == 0 || day == 6) {
            return "10:00"; // Weekend and not on vacation
        } else {
            return "7:00"; // Weekday and not on vacation
        }
    }
}

