    if (outsideMode) {
        // In outsideMode, return true if n is <= 1 or >= 10
        return n <= 1 || n >= 10;
    } else {
        // Otherwise, return true if n is between 1 and 10, inclusive
        return n >= 1 && n <= 10;
    }
}

