public boolean in1To10(int n, boolean outsideMode) {
    if (outsideMode) {
        // Return true if n is <= 1 or >= 10
        return n <= 1 || n >= 10;
    } else {
        // Return true if n is between 1 and 10, inclusive
        return n >= 1 && n <= 10;
    }
}

