public int sum67(int[] nums) {
    int sum = 0;
    boolean ignoreSection = false;

    for (int num : nums) {
        if (num == 6) {
            ignoreSection = true;
        }
        if (!ignoreSection) {
            sum += num;
        }
        if (num == 7 && ignoreSection) {
            ignoreSection = false;
        }
    }

    return sum;
}

