public int caughtSpeeding(int speed, boolean isBirthday) {
    // Adjust speed limit if it's your birthday
    int adjustedSpeed = isBirthday ? speed - 5 : speed;

    if (adjustedSpeed <= 60) {
        return 0; // No ticket
    } else if (adjustedSpeed <= 80) {
        return 1; // Small ticket
    } else {
        return 2; // Big ticket
    }
}

