public int dateFashion(int you, int date) {
    // If either of you has a fashion level of 8 or above, return "Yes" (2)
    if (you >= 8 || date >= 8) {
        return 2;
    }

    // If either of you has a fashion level of 2 or below, return "No" (0)
    if (you <= 2 || date <= 2) {
        return 0;
    }

    // Otherwise, return "Maybe" (1)
    return 1;
}

