        char currentChar = str.charAt(i);

        if (currentChar == 'y') {
            foundY = true;
        } else if (currentChar == 'x') {
            if (!foundY) {
                return false;
            }
        }
    }

    return true; // If no unbalanced 'x' is found, return true
}

