public int sum67(int[] nums) {
    int sum = 0;
    boolean ignoreSection = false;

    for (int num : nums) {
        if (ignoreSection) {
            if (num == 7) {
                ignoreSection = false;
            }
        } else {
            if (num == 6) {
                ignoreSection = true;
            } else {
                sum += num;
            }
        }
    }

    return sum;
}

