    boolean isBalanced = true;  // Assume it's balanced initially

    for (int i = 0; i < str.length(); i++) {
        char currentChar = str.charAt(i);

        if (currentChar == 'x') {
            isBalanced = false;  // Found an 'x', assume unbalanced until a 'y' is found
