Code:
public String alarmClock(int day, boolean vacation) {
    if (vacation) {
        // If on vacation
        if (day == 0 || day == 6) {
            // Weekend during vacation
            return "off";
        } else {
            // Weekday during vacation
            return "10:00";
        }
    } else {
        // If not on vacation
        if (day == 0 || day == 6) {
            // Weekend not on vacation
            return "10:00";
        } else {
            // Weekday not on vacation
            return "7:00";
        }
    }
}

